// TRF_PrepareMessages V2 - Robust fallback for empty responses
// Garantir envelope do trigger como fallback
let _triggerEnvelope = {};
try { _triggerEnvelope = $('TRG_FromOrchestrator').item.json.envelope || {}; } catch(e) {}

const input = $json;

// Get envelope - check multiple locations with fallback
const envelope = input.envelope 
  || input.qc_result?.envelope 
  || input.agent_response?.envelope
  || input.final_response?.envelope
  || _triggerEnvelope
  || {};

// Validate envelope
if (!envelope.from_phone) {
  // Last resort: try to find phone in any nested object
  const inputStr = JSON.stringify(input);
  const phoneMatch = inputStr.match(/55\d{10,11}/);
  if (phoneMatch) {
    envelope.from_phone = phoneMatch[0];
  } else {
    throw new Error('Envelope inválido: from_phone não encontrado.');
  }
}

// Get the text to send - check ALL possible locations with robust fallback
let textToSend = '';
let fallbackUsed = false;

// Priority 1: qc_result.final_text (from QC pipeline - most common)
if (input.qc_result?.final_text && input.qc_result.final_text.trim().length > 0) {
  textToSend = input.qc_result.final_text;
}
// Priority 2: qc_result.original_text (QC might have kept original)
else if (input.qc_result?.original_text && input.qc_result.original_text.trim().length > 0) {
  textToSend = input.qc_result.original_text;
}
// Priority 3: agent_response.text (direct from agent)
else if (input.agent_response?.text && input.agent_response.text.trim().length > 0) {
  textToSend = input.agent_response.text;
}
// Priority 4: final_response.text (legacy format)
else if (input.final_response?.text && input.final_response.text.trim().length > 0) {
  textToSend = input.final_response.text;
}
// Priority 5: summary (from WF06 capture)
else if (input.summary && input.summary.trim().length > 0) {
  textToSend = input.summary;
}
// Priority 6: text directly on input
else if (input.text && input.text.trim().length > 0) {
  textToSend = input.text;
}
// Priority 7: response_text (another possible field)
else if (input.response_text && input.response_text.trim().length > 0) {
  textToSend = input.response_text;
}
// Priority 8: Deep search in all string values
else {
  fallbackUsed = true;
  // Try to find any meaningful text in the input
  const candidates = [];
  function findTexts(obj, depth) {
    if (depth > 3 || !obj) return;
    if (typeof obj === 'string' && obj.trim().length > 10) {
      candidates.push(obj.trim());
    } else if (typeof obj === 'object') {
      for (const [key, val] of Object.entries(obj)) {
        if (['envelope', 'from_phone', 'to_phone', 'validation_flags'].includes(key)) continue;
        findTexts(val, depth + 1);
      }
    }
  }
  findTexts(input, 0);

  if (candidates.length > 0) {
    // Pick the longest candidate that looks like a message
    textToSend = candidates.sort((a, b) => b.length - a.length)[0];
  } else {
    textToSend = 'Hmm, tive um problema ao processar sua mensagem. Pode tentar novamente?';
  }
}

// Final safety: ensure text is not empty or just whitespace
if (!textToSend || textToSend.trim().length === 0) {
  textToSend = 'Hmm, tive um problema ao processar sua mensagem. Pode tentar novamente?';
  fallbackUsed = true;
}

// Format phone number for Z-API
let toPhone = envelope.from_phone;
if (!toPhone.includes('@')) {
  toPhone = toPhone.replace(/[^0-9]/g, '') + '@s.whatsapp.net';
}

return [{
  json: {
    envelope: envelope,
    to_phone: toPhone,
    text: textToSend,
    validation_flags: input.validation_flags || {},
    qc_result: input.qc_result || {},
    _fallback_used: fallbackUsed,
    _fallback_warning: fallbackUsed ? 'WARNING: Fallback response used - original response was empty' : null
  }
}];

// TRF_CheckSendResult - Check Z-API send result
const zapiResponse = $json;
const preparedData = $('TRF_PrepareMessages').item.json;

// Check if send was successful
const success = zapiResponse.zaapId || zapiResponse.messageId || zapiResponse.id;

return [{
  json: {
    envelope: preparedData.envelope,
    to_phone: preparedData.to_phone,
    text: preparedData.text,
    send_success: !!success,
    zapi_response: zapiResponse,
    sent_at: new Date().toISOString()
  }
}];

// TRF_BuildFinalResponse - Build final response
const preparedData = $('TRF_PrepareMessages').item.json;
const messages = preparedData.messages || [];

return [{
  json: {
    envelope: preparedData.envelope,
    dispatch_result: {
      messages_sent: messages.length,
      validation_flags: preparedData.validation_flags,
      qc_approved: preparedData.qc_result?.approved ?? true
    }
  }
}];
